INSERT INTO public.cost_centers (id, club_id, name, type, status, currency_code, start_date, created_at, updated_at)
SELECT gen_random_uuid(), (SELECT id FROM ac), n.name, 'evento'::cost_center_type, 'inactivo', 'ARS', '2024-01-01'::date, NOW(), NOW()
FROM new_ccs n
WHERE NOT EXISTS (SELECT 1 FROM public.cost_centers cc WHERE cc.club_id=(SELECT id FROM ac) AND lower(cc.name)=lower(n.name));